  ('disabled-57f41407-moex-00426', 'disabled-57f41407', 'disabled-57f41407-moex-112-55d283b0', 'sub-disabled-57f41407-03', NULL, 'single_choice', '關於民事簡易訴訟程序及其上訴審程序之敘述，下列何者正確？', '["關於財產權之訴訟，其標的金額在新臺幣60萬元以下者，適用簡易程序", "對於簡易訴訟程序之第一審裁判，得上訴至管轄之高等法院，其審判以 獨任庭行之", "對於簡易訴訟程序之第二審裁判，提起第三審上訴或抗告，應經原裁判 法院之許可", "對於簡易訴訟程序之第二審裁判，提起第三審上訴或抗告，應經原裁判法 院審判長之許可。但經當事人以書面聲明合意上訴至第三審者，不在此限"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:37+00:00", "source_pdf_sha1": "d2b7cdb0e0cd", "answer_pdf_sha1": "8efc4435d7d1", "source_family": "moex-gov-tw", "moex": {"exam_code": "112050", "c": "506", "s": "0310", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "112", "exam_name": "112年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 26, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "錄事"}'::jsonb, NULL),
  ('disabled-57f41407-moex-00427', 'disabled-57f41407', 'disabled-57f41407-moex-112-55d283b0', 'sub-disabled-57f41407-03', NULL, 'single_choice', '法律規範不能夠朝令夕改，否則人民無所適從，以上敘述，是關於法規範之 何種特性？', '["安定性", "普遍性", "強制性", "絕對性"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:37+00:00", "source_pdf_sha1": "d2b7cdb0e0cd", "answer_pdf_sha1": "8efc4435d7d1", "source_family": "moex-gov-tw", "moex": {"exam_code": "112050", "c": "506", "s": "0310", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "112", "exam_name": "112年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 27, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "錄事"}'::jsonb, NULL),
  ('disabled-57f41407-moex-00428', 'disabled-57f41407', 'disabled-57f41407-moex-112-55d283b0', 'sub-disabled-57f41407-03', NULL, 'single_choice', '依民事訴訟法第211條規定，參與言詞辯論之法官有變更者，當事人應陳 述以前辯論之要領。此一規定，係與民事訴訟法何項基本原則相關？', '["公開審理主義", "直接審理主義", "集中審理主義", "適時提出主義"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:37+00:00", "source_pdf_sha1": "d2b7cdb0e0cd", "answer_pdf_sha1": "8efc4435d7d1", "source_family": "moex-gov-tw", "moex": {"exam_code": "112050", "c": "506", "s": "0310", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "112", "exam_name": "112年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 28, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "錄事"}'::jsonb, NULL),
  ('disabled-57f41407-moex-00429', 'disabled-57f41407', 'disabled-57f41407-moex-112-55d283b0', 'sub-disabled-57f41407-03', NULL, 'single_choice', '依民事訴訟法規定，債權人向法院聲請發支付命令，債務人於支付命令送 達後，如何向法院提出異議？', '["債務人得於20日之不變期間內，附理由並檢具事證向發命令法院提出異議", "債務人得於20日之不變期間內，不附理由向發命令之法院提出異議", "債務人得於30日之不變期間內，附理由並檢具事證向發命令法院提出異議", "債務人得於30日之不變期間內，不附理由向發命令之法院提出異議"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:37+00:00", "source_pdf_sha1": "d2b7cdb0e0cd", "answer_pdf_sha1": "8efc4435d7d1", "source_family": "moex-gov-tw", "moex": {"exam_code": "112050", "c": "506", "s": "0310", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "112", "exam_name": "112年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 29, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "錄事"}'::jsonb, NULL),
  ('disabled-57f41407-moex-00430', 'disabled-57f41407', 'disabled-57f41407-moex-112-55d283b0', 'sub-disabled-57f41407-03', NULL, 'single_choice', '甲將乙市值新臺幣（下同）1萬元之陶土，燒製成市值1萬1千元之花瓶， 則該花瓶所有權屬於何者？', '["甲", "乙", "甲乙分別共有", "甲乙公同共有"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:37+00:00", "source_pdf_sha1": "d2b7cdb0e0cd", "answer_pdf_sha1": "8efc4435d7d1", "source_family": "moex-gov-tw", "moex": {"exam_code": "112050", "c": "506", "s": "0310", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "112", "exam_name": "112年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 30, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "錄事"}'::jsonb, NULL),
  ('disabled-57f41407-moex-00431', 'disabled-57f41407', 'disabled-57f41407-moex-112-55d283b0', 'sub-disabled-57f41407-03', NULL, 'single_choice', '甲對乙負有新臺幣（下同）120 萬元債務，由妻丙擔任保證人，好友丁則 提供價值 60 萬元土地設定普通抵押權於乙，嗣後甲未能還錢，乙向保證 人丙請求清償債務，丙為全額清償後，丙得向丁求償多少？', '["120萬元", "60萬元", "40萬元", "0元"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:37+00:00", "source_pdf_sha1": "d2b7cdb0e0cd", "answer_pdf_sha1": "8efc4435d7d1", "source_family": "moex-gov-tw", "moex": {"exam_code": "112050", "c": "506", "s": "0310", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "112", "exam_name": "112年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 31, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "錄事"}'::jsonb, NULL),
  ('disabled-57f41407-moex-00432', 'disabled-57f41407', 'disabled-57f41407-moex-112-55d283b0', 'sub-disabled-57f41407-03', NULL, 'single_choice', '關於民法所稱物之敘述，下列何者錯誤？', '["物可區分為動產及不動產", "違章建築因未辦理保存登記，故非屬不動產", "未完工房屋若足以遮避風雨而達經濟上使用目的時，仍屬不動產", "農地上果樹之果實未分離前，仍屬不動產之成分"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:37+00:00", "source_pdf_sha1": "d2b7cdb0e0cd", "answer_pdf_sha1": "8efc4435d7d1", "source_family": "moex-gov-tw", "moex": {"exam_code": "112050", "c": "506", "s": "0310", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "112", "exam_name": "112年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 32, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "錄事"}'::jsonb, NULL),
  ('disabled-57f41407-moex-00433', 'disabled-57f41407', 'disabled-57f41407-moex-112-55d283b0', 'sub-disabled-57f41407-03', NULL, 'single_choice', '關於民法上條件與期限之敘述，下列何者錯誤？', '["甲向乙表示，若乙順利通過國考，即贈乙汽車一台，此僅屬附停止條件 之贈與契約", "丙向丁表示，若建築執照無法申請通過，即終止承攬，此係屬附解除條 件之承攬契約", "戊向己表示，己於試用期滿表現良好後，才能正式受聘，此僅屬附始期 之僱傭契約", "庚向辛表示，辛須於明年除夕夜返還所借住之房屋，此係屬附終期之使 用借貸契約"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:37+00:00", "source_pdf_sha1": "d2b7cdb0e0cd", "answer_pdf_sha1": "8efc4435d7d1", "source_family": "moex-gov-tw", "moex": {"exam_code": "112050", "c": "506", "s": "0310", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "112", "exam_name": "112年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 33, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "錄事"}'::jsonb, NULL),
  ('disabled-57f41407-moex-00434', 'disabled-57f41407', 'disabled-57f41407-moex-112-55d283b0', 'sub-disabled-57f41407-03', NULL, 'single_choice', '甲贈送乙跑車一台。依民法規定，關於甲乙間法律關係之敘述，下列何者 錯誤？', '["甲若遲延給付，亦僅須交付該跑車", "若為不可歸責於甲之給付不能，甲免給付義務", "若因甲之抽象輕過失致其給付不能，甲應賠償贈與物之價額", "該跑車如有瑕疵，除甲故意不告知其瑕疵或保證其無瑕疵者外，甲不負 因瑕疵所生之損害賠償義務"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:37+00:00", "source_pdf_sha1": "d2b7cdb0e0cd", "answer_pdf_sha1": "8efc4435d7d1", "source_family": "moex-gov-tw", "moex": {"exam_code": "112050", "c": "506", "s": "0310", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "112", "exam_name": "112年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 34, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "錄事"}'::jsonb, NULL),
  ('disabled-57f41407-moex-00435', 'disabled-57f41407', 'disabled-57f41407-moex-112-55d283b0', 'sub-disabled-57f41407-03', NULL, 'single_choice', '甲與乙就甲所有之A屋外牆修繕工程，訂立承攬契約。乙完成並交付工作 後月餘，A屋外牆即有大量之磁磚掉落。關於甲乙間之承攬契約，下列何 者錯誤？', '["若A屋外牆磁磚掉落，係因乙偷工減料所致，甲無須先行定期催告乙修 補瑕疵，得逕依民法第495條請求損害賠償", "若A屋外牆磁磚掉落，係因甲所供給材料之性質而生，於乙不知材料有 問題之情況下，甲不得請求乙修補", "若A屋外牆磁磚掉落，係因乙偷工減料所致，甲定期催告乙修補而乙不 為修補，甲得自行修補，並請求乙償還修補必要之費用", "若A屋外牆磁磚掉落，係因乙偷工減料所致，甲雖定期催告乙修補，但 乙仍得因修補所需費用過鉅而拒絕修補"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:37+00:00", "source_pdf_sha1": "d2b7cdb0e0cd", "answer_pdf_sha1": "8efc4435d7d1", "source_family": "moex-gov-tw", "moex": {"exam_code": "112050", "c": "506", "s": "0310", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "112", "exam_name": "112年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 35, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "錄事"}'::jsonb, NULL)
